import { useRef, useCallback } from 'react';

/**
 * позволяет превратить функцию в вызываемую с дебаунсом
 *
 * @param callback функция, которую необходимо вызывать с дебаунсом
 * @param delay время задержки в миллисекундах
 *
 * @returns массив из двух элементов
 *
 * первый - переданный {@link callback}, вызываемый с задержкой
 *
 * второй - функция, позволяющая вручную отменить исполнение {@link callback} после задержки
 */
const useDebounceCallback = (callback, delay) => {
    const timeoutRef = useRef(null);
    const clearInnerTimeout = useCallback(() => {
        if (timeoutRef.current) {
            clearTimeout(timeoutRef.current);
        }
    }, [timeoutRef]);
    const throttledFunc = useCallback((...args) => {
        clearInnerTimeout();
        timeoutRef.current = setTimeout(() => {
            callback(...args);
            timeoutRef.current = null;
        }, delay);
    }, [timeoutRef, delay, callback, clearInnerTimeout]);
    return [throttledFunc, clearInnerTimeout];
};

export { useDebounceCallback };
